      case hashString("scrollEdgeAppearance"): return true;
      case hashString("minimizeBehavior"): return true;
      case hashString("tabBarHidden"): return true;
      case hashString("translucent"): return true;
      case hashString("barTintColor"): return true;
      case hashString("activeTintColor"): return true;
      case hashString("inactiveTintColor"): return true;
      case hashString("rippleColor"): return true;
      case hashString("activeIndicatorColor"): return true;
      case hashString("fontFamily"): return true;
      case hashString("fontWeight"): return true;
      case hashString("fontSize"): return true;
      case hashString("onPageSelected"): return true;
      case hashString("onTabLongPress"): return true;
      case hashString("onTabBarMeasured"): return true;
      case hashString("onNativeLayout"): return true;
      case hashString("hybridRef"): return true;
